(function(){const e=document.getElementById("theme-toggle"),t=document.documentElement,n=localStorage.getItem("theme")||"light";t.setAttribute("data-theme",n),s(n),e.addEventListener("click",function(){const n=t.getAttribute("data-theme"),e=n==="light"?"dark":"light";t.setAttribute("data-theme",e),localStorage.setItem("theme",e),s(e)});function s(t){e.textContent=t==="light"?"🌙":"☀️",e.setAttribute("aria-label",`Switch to ${t==="light"?"dark":"light"} mode`)}})()